import { Services_model } from "../model/model.js";
import { Services_view } from "../view/view.js";

export class Services_controller {
  constructor() {
    console.log("Services_controller working");

    this.model = new Services_model();
    this.view = new Services_view();

    this.model
      .fetch_anchor_tags()
      .then((res) => {
        if (res.elements) {
          this.view.render_anchor_tags(res.elements);
        }
      })
      .catch((err) => {
        console.log(err);
      });
  }
}
